import{_ as e,o as d,c as a,ag as o}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Serial Commands","description":"","frontmatter":{},"headers":[],"relativePath":"reference/serial-commands.md","filePath":"reference/serial-commands.md"}'),r={name:"reference/serial-commands.md"};function n(s,t,c,l,m,i){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="serial-commands" tabindex="-1">Serial Commands <a class="header-anchor" href="#serial-commands" aria-label="Permalink to &quot;Serial Commands&quot;">​</a></h1><p>Open the <strong>Serial Console</strong> from the patcher toolbar to send commands to the board. Type a command and press Enter.</p><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>STATUS</code></td><td>Show firmware version, CPU usage, current patch info, memory stats</td></tr><tr><td><code>PERF</code></td><td>Show real-time CPU performance (average, peak, glitch count)</td></tr><tr><td><code>MODULES</code></td><td>List all loaded modules with their types and IDs</td></tr><tr><td><code>GRAPH</code></td><td>Show the module routing graph (connections between modules)</td></tr><tr><td><code>HW</code></td><td>Show hardware state (pot values, button states, encoder position)</td></tr><tr><td><code>CLOCK</code></td><td>Show/set clock BPM and mode</td></tr><tr><td><code>RELOAD</code></td><td>Reload the current patch from storage</td></tr><tr><td><code>AUTO</code></td><td>Toggle auto-reload on patch change</td></tr><tr><td><code>POWERSAVE</code></td><td>Toggle power saving mode</td></tr><tr><td><code>LED</code></td><td>Test NeoPixel LEDs</td></tr><tr><td><code>MSTEST</code></td><td>MultiSample diagnostics (trigger test, slot info)</td></tr><tr><td><code>VERSION</code></td><td>Show firmware version</td></tr><tr><td><code>HELP</code></td><td>List available commands</td></tr></tbody></table><h2 id="parameter-control" tabindex="-1">Parameter Control <a class="header-anchor" href="#parameter-control" aria-label="Permalink to &quot;Parameter Control&quot;">​</a></h2><p>You can set module parameters directly from the serial console:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PARAM &lt;moduleId&gt; &lt;paramName&gt; &lt;value&gt;</span></span></code></pre></div><p>Example: <code>PARAM osc1 freq 880</code> sets oscillator 1&#39;s frequency to 880 Hz.</p><h2 id="midi-commands" tabindex="-1">MIDI Commands <a class="header-anchor" href="#midi-commands" aria-label="Permalink to &quot;MIDI Commands&quot;">​</a></h2><p>Send MIDI messages from the serial console:</p><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>MIDICC &lt;cc&gt; &lt;value&gt;</code></td><td>Send a MIDI CC message (0-127)</td></tr><tr><td><code>MIDINOTE &lt;note&gt; &lt;1|0&gt;</code></td><td>Send note on/off</td></tr><tr><td><code>MIDITAP &lt;note&gt;</code></td><td>Send a 100ms momentary note</td></tr></tbody></table><h2 id="file-commands" tabindex="-1">File Commands <a class="header-anchor" href="#file-commands" aria-label="Permalink to &quot;File Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>LS [path]</code></td><td>List files in a directory on the SD card</td></tr><tr><td><code>FILE_SEND &lt;path&gt;</code></td><td>Download a file from SD (base64 encoded)</td></tr><tr><td><code>FILE_DELETE &lt;path&gt;</code></td><td>Delete a file from SD</td></tr></tbody></table>',13)])])}const u=e(r,[["render",n]]);export{p as __pageData,u as default};
